from typing import List

def parse_nested_parens(paren_string: str) -> List[int]:
    stack = []
    levels = []
    for char in paren_string:
        if char == '(':
            stack.append(len(stack) + 1)
        elif char == ')':
            stack.pop()
            levels.append(len(stack) - 1)
    return levels
